#!/usr/bin/perl

use strict;
use warnings;
use CGI;

my $q = CGI->new;

my $log_dir = "/var/log"; # Customize this directory as needed

print $q->header;
print $q->start_html('Log File Viewer');

my $filename = $q->param('logfile');

if (defined $filename && $filename ne '') {
    # Basic sanitization: only allow alphanumeric, hyphens, underscores, dots
    # This is not fully secure; a more robust solution would use a whitelist
    # of allowed files or a directory traversal prevention mechanism.
    if ($filename =~ m#^[a-zA-Z0-9_\-\.]+$#) {
        my $filepath = "$log_dir/$filename";

        if (-f $filepath && -r $filepath) {
            print "<h2>Displaying Log: " . $q->escapeHTML($filename) . "</h2>";
            print "<pre>";
            if (open(my $fh, "<", $filepath)) {
                while (my $line = <$fh>) {
                    print $q->escapeHTML($line);
                }
                close($fh);
            } else {
                print "Error opening file: " . $q->escapeHTML($!
) . "\n";
            }
            print "</pre>";
        } else {
            print "<h2>Error: File not found or not readable: " . $q->escapeHTML($filename) . "</h2>";
        }
    } else {
        print "<h2>Error: Invalid filename parameter.</h2>";
    }
} else {
    print "<h2>Please specify a log file using the 'logfile' parameter.</h2>";
    print "<p>Example: <a href=\"?logfile=syslog\">?logfile=syslog</a></p>";
}

print $q->end_html;